const sendgridApiKey = ENV.SENDGRID_API_KEY;
const stripeApiKey = ENV.STRIPE_API_KEY;

async function sendEmail(to, subject, text) {
    const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
        method: 'POST',
        headers: {
            'Authorization': `Bearer ${sendgridApiKey}`,
            'Content-Type': 'application/json',
        },
        body: JSON.stringify({
            personalizations: [{ to: [{ email: to }] }],
            from: { email: 'noreply@example.com' },
            subject: subject,
            content: [{ type: 'text/plain', value: text }],
        }),
    });

    if (!response.ok) {
        throw new Error(`SendGrid error: ${response.statusText}`);
    }
}

async function processPayment(amount, currency, source) {
    const response = await fetch('https://api.stripe.com/v1/charges', {
        method: 'POST',
        headers: {
            'Authorization': `Bearer ${stripeApiKey}`,
            'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
            amount: amount,
            currency: currency,
            source: source,
        }),
    });

    if (!response.ok) {
        throw new Error(`Stripe error: ${response.statusText}`);
    }

    return await response.json();
}

addEventListener('fetch', event => {
    event.respondWith(handleRequest(event.request));
});

async function handleRequest(request) {
    try {
        const { method, url } = request;

        if (method === 'POST' && url.endsWith('/send-email')) {
            const { to, subject, text } = await request.json();
            await sendEmail(to, subject, text);
            return new Response('Email sent successfully', { status: 200 });
        }

        if (method === 'POST' && url.endsWith('/process-payment')) {
            const { amount, currency, source } = await request.json();
            const paymentResult = await processPayment(amount, currency, source);
            return new Response(JSON.stringify(paymentResult), { status: 200 });
        }

        return new Response('Not Found', { status: 404 });
    } catch (error) {
        return new Response(error.message, { status: 500 });
    }
}